mapper.select:
/* SmsBadwordMapper.getBadwordManageList */ SELECT ID, KEYWORD, KEYWORD_NORMALIZED, CATEGORY, MATCH_TYPE, SEVERITY, SOURCE, IS_ACTIVE
FROM BADWORD WHERE 1=1
AND KEYWORD LIKE '%' || #{keyword} || '%'
AND CATEGORY = #{category}
AND MATCH_TYPE = #{matchType}
AND SEVERITY = #{severity}
AND IS_ACTIVE = #{isActive}
ORDER BY ID

mapper.delete:
/* SmsBadwordMapper.deleteBadwordManage */
DELETE FROM BADWORD
WHERE   ID = #{id}

mapper.select:
/* SmsBadwordMapper.getMsgBlockLogList */
SELECT L.ID, L.ACCOUNT_ID, L.MESSAGE_ID, L.BLOCK_TYPE, L.TRIGGERED_KEYWORD_ID, B.KEYWORD AS TRIGGERED_KEYWORD, L.TRIGGERED_URL, L.URL_CHECK_SOURCE, L.STATUS, L.ADMIN_REVIEW_ID, L.MESSAGE_SNIPPET, TO_CHAR(TO_DATE(L.CREATED_AT, 'yyyymmddhh24miss'), 'yyyy-mm-dd hh24:mi:ss') AS CREATED_AT, L.SMS_SEND_SEQ, SBPENC.D(L.CALLBACK) AS CALLBACK, L.S_OGN_CD, L.S_OGN_FG, L.S_USER_ID
FROM MESSAGE_BLOCK_LOG L LEFT OUTER JOIN BADWORD B ON B.ID = L.TRIGGERED_KEYWORD_ID WHERE 1=1
AND TO_DATE(L.CREATED_AT, 'YYYYMMDDHH24MISS') >= TO_DATE(#{startDate}, 'YYYYMMDD')
AND TO_DATE(L.CREATED_AT, 'YYYYMMDDHH24MISS') < TO_DATE(#{endDate}, 'YYYYMMDD') + 1
AND L.BLOCK_TYPE = #{blockType}
AND B.KEYWORD LIKE '%' || #{triggeredKeyword} || '%'
AND L.TRIGGERED_URL LIKE '%' || #{triggeredUrl} || '%'
AND L.STATUS = #{msgStatus}
ORDER BY L.CREATED_AT DESC
